      if (!filterDef) return;

      const dbField = mapFieldToColumn(field);
      const condition = buildCondition(filterDef);
      if (!condition) return;

      // ✅ EXACT SAME REGEX AS ItemLibrary
      const match = dbField.match(/^merchGroup0([1-6])/);
      if (match) {
        const key = `merchGroup0${match[1]}`;
        merchGroupFilters[key] = condition;
      } else {
        whereClause[dbField] = condition;
      }
    });

    // 🔹 Division codes (same pattern)
    const andConditions = [];
    const divisionCodeIds = req.query.divisionCodeIds
      ? JSON.parse(req.query.divisionCodeIds)
      : [];

    if (divisionCodeIds.length > 0) {
      (divisionCodeIds.includes(1)) ? divisionCodeIds.push(2) : null;
      andConditions.push({
        [Op.or]: [
          { div_code_fk: { [Op.in]: divisionCodeIds } },
          { div_code_fk: null }
        ]
      });
    }

    if (andConditions.length > 0) {
      whereClause[Op.and] = andConditions;
    }

    // 🔹 SAME merchGroup include generator
    const generateMerchGroupIncludes = () =>
      Object.entries(merchGroupFilters).map(([key, filter]) => {
        const match = key.match(/^merchGroup0([1-6])/);
        const hasFilter = Reflect.ownKeys(filter).length > 0;

        return {
          model: sql.merchGroup,
          as: key,
          required: hasFilter,
          where: hasFilter
            ? {
                mgTypeCode: `0${match[1]}`,
                mg_desc: filter
              }
            : undefined
        };
      });

    const merchIncludes = generateMerchGroupIncludes();

    // 🔹 Single query for both count and data
    const { count, rows } = await sql.itemHeader.findAndCountAll({
      where: whereClause,
      logging: console.log,
      order: [['item_id_pk', 'DESC']],
      limit,
      offset,
      distinct: true,
      include: [
        { model: sql.externalVendor, as: 'externalVendor' },
        { model: sql.itemAttachment, as: 'itemAttachments' },
        { model: sql.itemLicenseImage, as: 'licenseImages', required: false },
        { model: sql.comments, as: 'comments', required: false },
        {
          model: sql.licensingStatus,
          as: 'licensingStatuses',
          required: !!(filters?.license_status?.values?.length),
          where: {
            ...(filters?.license_status?.values?.length ? {
              status: { [Op.in]: filters.license_status.values }
            } : {}),
            id: { [Op.eq]: Sequelize.literal(`(
              SELECT MAX(id) 
              FROM "${process.env.SCHEMA}"."licensingStatus" AS "ls" 
              WHERE CAST("ls"."itemheader_id_fk" AS INTEGER) = "itemHeader"."item_id_pk"
            )`) }
          }
        },
        ...merchIncludes
      ]
    });

    const colHeaders = await getGridHeader(['licensing_tracking']);
    const licensorGroups = await sql.merchGroup.findAll({
      where: {
        mgTypeCode: '05',
        divisionCode_id_fk: { [Op.in]: [1, 8] }
      }
    });

    const remappedData = await utility.remapLicItem(
      colHeaders,
      rows,
      licensorGroups
    );

    result(null, {
      rows: remappedData,
      totalCount: count
    });
  } catch (err) {
    console.error('Error in getAllLicenses:', err);
    result(null, err);
  }
};



