const mapFieldToColumn = (field) => {
  const fieldMap = {
    'item_num_id': 'item_num_id',
    'item_desc': 'item_displ_descr_name',
    'brand_assurance_number': 'udf_freeform_03',
    'licensorCode': 'merchGroup05.udf_merchgroup05_fk_id',
    'comment': 'lic_comment',
    'season': 'season_code_fk',
    'for_cust': 'udf_merchgroup15_fk',
    'sample_no': 'lic_sample_no',
    'due_date': 'due_date',
    'updated_date': 'lic_tracking_updated_date',
    'on_shelf_date': 'udf_date01'
  };

  return fieldMap[field] || field;
};

