// Images: add a new image record
LicTracking.addLicenseImage = async (req, result) => {
  try {
    const user = await getUserInfo(req.headers.authorization);
    const item_num_id_fk = Number(req.body.itemheader_id_fk);
    const image_link = req.body.image_link || req.body.sharedLink || req.body.imageUrl || req.body.url;
    const thumb_link = req.body.thumb_link || req.body.thumbSharedLink || req.body.thumbnailUrl || req.body.thumbnail;

    if (!item_num_id_fk || !image_link || !thumb_link) {
      return result({ message: 'itemheader_id_fk, image_link and thumb_link are required' });
    }

    const [itemHeader] = await Promise.all([
      sql.itemAttachment.findOne({
        where: { item_num_id_fk },
        order: [['item_attachment_id', 'ASC']]
      }),
      sql.itemHeader.findByPk(item_num_id_fk, { attributes: ['compan_code_fk', 'div_code_fk'] })
    ]);

    const created_user = req.body.created_user || user?.name || null;
    const created_time = req.body.created_time ? new Date(req.body.created_time).getTime() : Date.now();
    const companyCode_name = itemHeader?.compan_code_fk || 'EDGEHOME';
    const divisionCode_name = itemHeader?.div_code_fk;
    const uuid = uuidv4();

    const buildAttachmentPayload = (link, displayName) => {
      if (!link) return null;
      const fileName = (link.split('/').pop() || '').split('?')[0];
      const extension = (fileName.split('.').pop() || '').toLowerCase() || 'jpeg';
      const attachment_type = displayName === 'Thumb' ? `image/${extension}` : extension;

      return {
        attachment_type,
        attachment_display_name: displayName,
        attachment_link: link,
        item_num_id_fk,
        item_attachment_createdTime: created_time,
        item_attachment_createdUser: created_user,
        item_attachment_modTime: created_time,
        item_attachment_modUser: created_user,
        item_attachment_fileName: fileName,
        companyCode_name,
        divisionCode_name,
        item_attachment_colorCode: '',
        item_attachment_resourceId: 1,
        primary_image: false,
        uuid
      };
    };

    const attachments = [
      buildAttachmentPayload(image_link, 'Image'),
      buildAttachmentPayload(thumb_link, 'Thumb')
    ].filter(Boolean);

    const createdRows = [];
    for (const attachment of attachments) {
      const [row] = await sql.itemAttachment.findOrCreate({
        where: {
          item_num_id_fk: attachment.item_num_id_fk,
          attachment_display_name: attachment.attachment_display_name,
          attachment_link: attachment.attachment_link,
        },
        defaults: attachment
      });
      createdRows.push(row.get({ plain: true }));
    }

    return result(null, createdRows);
  } catch (err) {
    console.error('addLicenseImage error', err);
    return result(err);
  }
}

LicTracking.getSelectedGridView = async (req, result) => {
  try {

    const layoutName = req.query.layout_name;
    const gridId = req.query.grid_id;

    const user_info = await getUserInfo(req.headers.authorization);

    // Build base condition
    let condition = {
      user_id_fk: layoutName !== "Default" ? user_info.user_id : null,
      layout_name: layoutName,
      grid_id: gridId,
    };

    const data = await sql.GridAccessLevel.findAll({
      order: [Sequelize.literal("col_order ASC")],
      where: {
        col_access_level: user_info.role,
        grid_id: gridId,
        access: true,
      },
      include: [
        {
          model: sql.GridLayout,
          as: "GridLayouts",
          where: condition,
        },
      ],
    });

    if (data && data.length > 0) {
      const newData = data.map((d) => d.dataValues.GridLayouts[0].dataValues);
      const reordered = await utility.reorderColumns(newData, gridId);
      const data_map = await utility.RemapCustomGridLayoutData(reordered);
      return result(null, data_map);
    } else {
      return result(null, []);
    }
  } catch (err) {
    console.error("Error in getSelectedGridView:", err);
    return result(err);
  }
};



